117   if (Val.isOverdefined())
118     return OS << "overdefined";
119 
120   if (Val.isNotConstant())
121     return OS << "notconstant<" << *Val.getNotConstant() << ">";
122 
123   if (Val.isConstantRangeIncludingUndef())
124     return OS << "constantrange incl. undef <"
